import { HttpClient } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { Capacitor } from "@capacitor/core";
import { AlertController } from "@ionic/angular";
import { GeolocationResult } from "src/app/core/models/IntentResults/GeolocationResult";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { LocationService } from "src/app/core/services/location.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { IClientDueToday } from "src/app/views/Models/Client/ClientDueToday";
import { pagingService } from "src/app/core/services/paging.service";

@Component({
  selector: "app-clients-due-today-tracker",
  templateUrl: "./clients-due-today-tracker.page.html",
  styleUrls: ["./clients-due-today-tracker.page.css"],
})
export class ClientsDueTodayTrackerPage implements OnInit {
  clients = [];
  showLoader: boolean = false;

  ClientsDueTodayForm: FormGroup;
  startDate: string = null;
  endDate: string = null;

  pageSize : number; // number of viewed results
  page = 1; // the page we are viewing
  resultsCount; // the nuber of results
  totalPages = 1; // calculate by the pageSize and resultcount this.totalPages = (Math.trunc(x) < (this.resultsCount/this.pageSize)) ? Math.trunc(x)+1:Math.trunc(x) ;

  sortingParam: string = "distance";
  orderBy: boolean = false;

  OfficerLong;
  OfficerLat;
  OfficerZoom;
  officer_key: string;
  cur_branch_code: string;

  constructor(
    private env: EnvService,
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private alertController: AlertController,
    private locationService: LocationService,
    private alertSerivce: AlertService,
    private AuthService: MohassilAuthService,
    private pagingService: pagingService
  ) {}

  async ngOnInit() {
    this.pageSize = this.pagingService.getPageSizeFromLocalStorage();
    await this.formatForm();
    await this.getOfficerLocation();
    await this.userInfo();
    await this.GetClientsDueToday();
  }

  async userInfo() {
    this.officer_key = (await this.AuthService.getUserInfo()).officer_key;
    this.cur_branch_code = (await this.AuthService.getUserInfo()).branch_code;
  }

  formatForm() {
    this.ClientsDueTodayForm = this.formBuilder.group({
      startDate: [null],
      endDate: [null],
    });
  }

  GetClientsDueToday() {
    this.showLoader = true;

    var ClientDueToday: IClientDueToday = {
      end_date: this.ClientsDueTodayForm.controls.endDate.value,
      start_date: this.ClientsDueTodayForm.controls.startDate.value,
      cur_inst_status: "1,2,6",
      cur_inst_cond: "0",
      cur_currency_code: "0",
      cur_client_type: "0",
      cur_officer_key: this.officer_key,
      cur_branch_code: this.cur_branch_code,
      ls_loan_type: "0",
      all_loan_types: "1",
      ls_funder: "0",
      all_funder: "1",
      OfficerLat: this.OfficerLat,
      OfficerLong: this.OfficerLong,
    };

    this.http
      .post<IClientDueToday>(
        this.env.API_URL +
          `api/Clients/ClientsDueToday?&pageNo=${this.page}&pageSize=${this.pageSize}&sortingParam=${this.sortingParam}&orderBy=${this.orderBy}`,
        ClientDueToday
      )
      .subscribe({
        next: (data) => {
          // this.reset();
          this.clients = data["result"];
          // console.log(this.clients);
          this.resultsCount = data["count"];

          // this.sortDistance();
          // this.success("تم اضافة طلب القرض بنجاح");
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.error);
          // this.fail(err.error);
          this.showLoader = false;
        },
      });
  }

  async getOfficerLocation(): Promise<void> {
    // if (Capacitor.getPlatform() != "web") {
    this.showLoader = true;
    try {
      let locationResult: GeolocationResult =
        await this.locationService.getLocation();
      // console.log(locationResult);
      if (!locationResult.success) {
        this.alertSerivce.showAlertError(locationResult.message, false);
        this.showLoader = false;
        return;
      }

      this.OfficerLat = locationResult.position?.coords.latitude.toString();
      this.OfficerLong = locationResult.position?.coords.longitude.toString();
      this.OfficerZoom = "0";
      // console.log(this.OfficerLat, this.OfficerLong,"off");
      // this.presentToast("تم", locationResult.message);
      this.showLoader = false;
    } catch (error) {
      this.showLoader = false;
    }
    // }
  }

  sortByDistance() {
    this.sortingParam = "distance";
    this.orderBy = !this.orderBy;
    this.GetClientsDueToday();
  }

  sortByAmount() {
    this.sortingParam = "Total";
    this.orderBy = !this.orderBy;
    this.GetClientsDueToday();
  }

  changePage(newPage: number): void {
    this.page = newPage;
  }

  async showHomeLocation(home_Lat, home_Long): Promise<void> {
    let coordinates: string = `${home_Lat},${home_Long}`;
    let result = await this.locationService.showLocation(coordinates);
    if (!result.success) {
      this.alertSerivce.showAlertError(result.message, false);
    }
  }
}
